INSERT INTO formations (id_formation, titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) SELECT gen_random_uuid(), v.* FROM (VALUES ('Concevoir et piloter un projet Big Data', 'Formation sur les techniques modernes de vente et de négociation commerciale.', 3, 200000.00, 'entreprise', '2026-11-10', 30, '2026-01-14 12:37:32', '2026-02-18 23:44:04', NULL, E'--- OBJECTIFS ---\n• Maîtriser les étapes clés du processus commercial\n• Développer des compétences en prospection et fidélisation\n• Adapter l’argumentaire et le style de négociation selon le client\n• Gérer les objections et conclure efficacement les ventes\n• Construire des relations commerciales durables et orientées résultats\n\n--- OBJECTIFS DÉTAILLÉS ---\nMaîtriser les techniques de vente moderne, développer des compétences en prospection et fidélisation, adapter l’argumentaire et la négociation selon le profil client, gérer les objections et conclure efficacement les ventes.\n\n--- PRÉREQUIS ---\nExpérience préalable en vente ou relation client souhaitée.\n\n--- CONTENU ---\nModule 1 : Introduction à la vente moderne\nModule 2 : Prospection et qualification des clients\nModule 3 : Argumentation et présentation commerciale\nModule 4 : Gestion des objections et traitement des résistances\nModule 5 : Techniques de négociation commerciale\nModule 6 : Conclusion de la vente et fidélisation\nModule 7 : Suivi et analyse des performances commerciales\n\n--- NIVEAU ---\nTous niveaux\n\n--- PUBLIC ---\nCommerciaux, représentants, responsables commerciaux, chefs d’équipe et toute personne impliquée dans la vente et la négociation.\n\n--- MÉTHODES ---\nPrésentations interactives, ateliers pratiques, jeux de rôle, simulations commerciales, études de cas et feedback individualisé.\n\n--- SUPPORTS ---\nManuel du participant, fiches pratiques, modèles d’argumentaires, scripts de prospection, CRM, tableaux de bord commerciaux, supports PDF et vidéos pédagogiques.\n\n--- CERTIFICATION ---\nAttestation de participation remise par ISD Groupe', 'ba52f30c-c061-41b8-b0f7-afa6eca6fa76')) AS v(titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) WHERE NOT EXISTS (SELECT 1 FROM formations f WHERE f.titre = v.titre AND f.date_debut = v.date_debut::date);
